#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-18

# tests/hooks/test-native-binary-compat.sh
# Guards against hook-code patterns that break when CC 2.1.113+ spawns
# the native platform binary instead of the bundled JS runtime.
#
# Background: Before 2.1.113, CC was a node.js script launched via a
# wrapper. Hooks that inspected process.argv[0] == 'node', __dirname
# relative to node_modules/.bin/claude, or require.resolve() paths
# happened to work. After 2.1.113 the CLI is a compiled native binary —
# those paths change, and hooks that relied on them break silently.
#
# Safe pattern for ESM shims: derive __dirname from import.meta.url via
# fileURLToPath. That works identically under either spawn mode.
set -euo pipefail

PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)}"
HOOK_SRC="$PROJECT_ROOT/src/hooks/src"
HOOK_BIN="$PROJECT_ROOT/src/hooks/bin"

RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[0;33m'
NC='\033[0m'

PASS=0
FAIL=0

pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo -e "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }
warn() { echo -e "  ${YELLOW}!${NC} $1"; }

echo "Native-Binary Compatibility (CC 2.1.113+)"
echo "=========================================="

# Files to scan: production hook source only. Exclude:
# - __tests__/ (test code is not hot path)
# - dist/ (build artifacts)
# - cc-version-matrix.ts (metadata-only — descriptions mention banned
#   patterns as documentation, which would false-positive)
HOOK_FILES=$(find "$HOOK_SRC" -type f \( -name '*.ts' -o -name '*.mjs' \) \
  ! -path '*/__tests__/*' ! -path '*/dist/*' \
  ! -name 'cc-version-matrix.ts' 2>/dev/null || true)
SHIM_FILES=$(find "$HOOK_BIN" -type f -name '*.mjs' 2>/dev/null || true)

if [[ -z "$HOOK_FILES" ]]; then
  fail "No hook source files found at $HOOK_SRC"
  exit 1
fi

# Banned patterns — will break when spawned by native binary
# 1. process.argv0 (native binary's argv0 is not 'node')
# 2. process.execPath checks against 'node'
# 3. require.resolve() — CommonJS-only, native binary uses ESM
# 4. References to node_modules/.bin/ paths in hot-path logic
check_pattern() {
  local pattern="$1"
  local desc="$2"
  local matches
  matches=$(echo "$HOOK_FILES" | xargs grep -nE "$pattern" 2>/dev/null | grep -v '^\s*\(//\|\*\)' || true)
  if [[ -n "$matches" ]]; then
    fail "$desc"
    echo "$matches" | sed 's/^/      /' | head -5
    if [[ $(echo "$matches" | wc -l) -gt 5 ]]; then
      echo "      ... ($(echo "$matches" | wc -l) total matches)"
    fi
  else
    pass "$desc"
  fi
}

check_pattern 'process\.argv0' 'No process.argv0 reads in hot path (native binary argv0 differs)'
check_pattern 'process\.execPath.*node' 'No process.execPath matching on node (native binary path differs)'
check_pattern '\brequire\.resolve\(' 'No require.resolve() calls (ESM-native under 2.1.113+)'
check_pattern 'node_modules/\.bin/claude' 'No hard-coded references to bundled claude binary path'

# Shim check: run-hook.mjs MUST use import.meta.url (not process.argv[1])
# to compute __dirname, so it works identically under both spawn modes.
if [[ -n "$SHIM_FILES" ]]; then
  if echo "$SHIM_FILES" | xargs grep -l 'import\.meta\.url' >/dev/null 2>&1; then
    pass 'Hook shim uses import.meta.url for path resolution (ESM-safe)'
  else
    warn 'Hook shim does not use import.meta.url — verify path resolution under native spawn'
  fi
fi

echo ""
echo "=========================================="
echo "  Passed: $PASS"
echo "  Failed: $FAIL"
echo "=========================================="

if [[ $FAIL -gt 0 ]]; then
  exit 1
fi
